code.JavaScript:
const readline = require('readline');
const rl = readline.createInterface({
    input: process.stdin,
    output: process.stdout
});
let n, m;
let grid = [];
let count = 0;
rl.on('line', (line) => {
    if (!n) {
        [n, m] = line.split(' ').map(Number);
    } else {
        grid.push(line);
        if (grid.length === n) {
            for (let i = 0; i < n; i++) {
                for (let j = 0; j < m; j++) {
                    if (grid[i][j] === '#') {
                        count++;
                    }
                }
            }
            console.log(count);
            rl.close();
        }
    }
});
